SELECT 
FROM cart_items ci
JOIN products p ON ci.product_id = p.id
WHERE ci.user_id = #{userId}
  AND ci.product_id = #{productId}
LIMIT 1

SELECT 
FROM cart_items ci
JOIN products p ON ci.product_id = p.id
WHERE ci.user_id = #{userId}
  AND ci.product_id = #{productId}
  AND (
    (#{selectedSpecs} IS NULL AND ci.selected_specs IS NULL)
    OR ci.selected_specs = #{selectedSpecs}
  )
LIMIT 1

mapper.update:
UPDATE cart_items
SET quantity = #{quantity},
    price = #{price},
    updated_at = #{updatedAt}
WHERE id = #{id}
